// Rise 6.0 - reading S0B for critical detection:
if (event.getPacket() instanceof S0BPacketAnimation) {
    S0BPacketAnimation s0b = (S0BPacketAnimation) event.getPacket();
    if (s0b.getEntityID() == mc.thePlayer.getEntityId()) {
        int animType = s0b.getAnimationType();
        if (animType == 4 || animType == 5) {
            // Critical hit registered on our player
            lastCriticalTime = System.currentTimeMillis();
        }
    }
}
// Vanilla S0BPacketAnimation:
public class S0BPacketAnimation implements Packet<INetHandlerPlayClient> {
    private int entityId;
    private int type;
    public S0BPacketAnimation() {}
    public S0BPacketAnimation(Entity entityIn, int typeIn) {
        this.entityId = entityIn.getEntityId();
        this.type = typeIn;
    }
    public void processPacket(INetHandlerPlayClient h) { h.handleAnimation(this); }
    public int getEntityID() { return this.entityId; }
    public int getAnimationType() { return this.type; }
}
